{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream bounded contexts that consume shipment data, and external partner integrations. This is not a simple schema migration — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment Management (core domain). Ripple effects into: Routing & Dispatch, Notifications, Billing, Partner Integration, and Tracking.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods moving from an origin to one or more recipients. After this change, a Shipment is no longer synonymous with a single delivery — it becomes a container for multiple deliveries." },
      { "term": "Recipient", "definition": "A person or entity receiving part or all of a Shipment, identified by name, address, phone number, and now also individual delivery preferences." },
      { "term": "Delivery Preference", "definition": "Recipient-level configuration governing how and when delivery should occur (e.g., time window, leave-at-door, signature required). This is NEW — previously implicit at the Shipment level." },
      { "term": "Primary Recipient", "definition": "AMBIGUOUS — see escalations. May or may not exist. If multi-recipient shipments have no designated primary, this changes accountability and notification models." },
      { "term": "Shipment Status", "definition": "The aggregate delivery state of a Shipment. With multiple recipients, status semantics change: a Shipment may be partially delivered, which is a new state that did not previously exist." },
      { "term": "Partner Payload", "definition": "The data structure sent to external partner APIs describing a shipment. Currently assumes a single recipient. Must be versioned or adapted." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with no recipient has no physical destination. It cannot be routed, dispatched, or delivered. This is a physical constraint of the logistics domain.",
      "testable_assertion": "Any attempt to create or update a Shipment to have zero Recipients must be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically deliver goods and contact the recipient. Without them, last-mile delivery is impossible.",
      "testable_assertion": "Creating a Recipient with a null or empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment MUST have exactly one set of delivery preferences (explicit or default).",
      "invariant": true,
      "invariant_justification": "Delivery preferences drive routing, scheduling, and courier behavior. Ambiguous preferences for a recipient create unsafe delivery conditions.",
      "testable_assertion": "A Recipient without delivery preferences must receive system defaults upon creation. A Recipient must never exist with null delivery preferences."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient shipments must remain valid and fully functional without modification after migration.",
      "invariant": true,
      "invariant_justification": "2 million shipments in production represent real-world obligations. Corrupting or invalidating them breaks contractual commitments and operational continuity.",
      "testable_assertion": "After migration, all existing shipments must be queryable, updatable, and deliverable with identical behavior to pre-migration."
    },
    {
      "id": "BR-5",
      "rule": "Shipment-level status must reflect the aggregate state of all Recipient deliveries. A Shipment is 'Delivered' only when ALL Recipients have received their delivery.",
      "invariant": false,
      "invariant_justification": "This is a business policy. Some businesses may define 'delivered' as majority-delivered or primary-recipient-delivered. A VP could change this threshold.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must NOT have status 'Delivered'."
    },
    {
      "id": "BR-6",
      "rule": "A new 'Partially Delivered' status must exist for Shipments where at least one but not all Recipients have been delivered.",
      "invariant": false,
      "invariant_justification": "This is a policy-level status. The business could choose to model this differently (e.g., percentage-based, or per-recipient status only).",
      "testable_assertion": "A Shipment with 3 Recipients where 1 is delivered and 2 are pending must have status 'Partially Delivered'."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until partners have migrated to the new format.",
      "invariant": false,
      "invariant_justification": "This is a compatibility policy, not a physical constraint. Partners could be forced to migrate, but the business chooses backward compatibility.",
      "testable_assertion": "For multi-recipient shipments sent to non-migrated partners, the system must either send one payload per recipient or send only the primary recipient. The chosen strategy must be explicitly defined."
    },
    {
      "id": "BR-8",
      "rule": "Recipient addresses within a single Shipment may be different locations. The routing engine must handle multi-stop deliveries.",
      "invariant": true,
      "invariant_justification": "This is the entire point of multi-recipient support. If addresses must be identical, the feature has no value. Different addresses are a physical reality the routing system must handle.",
      "testable_assertion": "A Shipment with Recipients at addresses A, B, and C must generate a multi-stop route, not three separate shipments."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies 3 Recipients with distinct addresses and delivery preferences",
      "then": "The Shipment is created with all 3 Recipients, each preserving their individual preferences, and a multi-stop route is generated"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment from before the migration",
      "when": "The system reads this Shipment",
      "then": "It is returned as a Shipment with a Recipients collection containing exactly one Recipient, with default delivery preferences applied, and all existing behavior is unchanged"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient 1 has been delivered but Recipients 2 and 3 have not",
      "when": "The Shipment status is queried",
      "then": "The Shipment status is 'Partially Delivered' and each Recipient shows their individual delivery status"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment",
      "when": "An external partner API that has NOT migrated requests this Shipment's data",
      "then": "The partner receives data in the legacy single-recipient format according to the defined backward-compatibility strategy, with no breaking schema changes"
    },
    {
      "id": "AC-5",
      "given": "A Shipment creation request with zero Recipients",
      "when": "The request is submitted",
      "then": "The request is rejected with a clear validation error: 'A Shipment must have at least one Recipient'"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment where all Recipients have been delivered",
      "when": "The last Recipient delivery is confirmed",
      "then": "The Shipment status transitions to 'Delivered' and all stakeholders are notified of completion"
    },
    {
      "id": "AC-7",
      "given": "The production database with ~2 million existing single-recipient shipments",
      "when": "The data migration runs",
      "then": "All 2 million shipments are migrated to the new schema with zero data loss, each having exactly one Recipient in the new collection structure, and default delivery preferences assigned"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where one Recipient's delivery fails permanently (e.g., address unreachable) but others succeed.",
      "expected_behavior": "The Shipment must not be marked 'Delivered'. The failed Recipient must be flagged individually. Business must define: does the entire Shipment fail, or does it remain 'Partially Delivered' indefinitely? Escalation needed."
    },
    {
      "scenario": "Two Recipients on the same Shipment have conflicting delivery preferences (e.g., Recipient A wants morning delivery, Recipient B wants evening) and live at the same address.",
      "expected_behavior": "The system must not silently merge them. Each Recipient is a distinct delivery obligation. Routing must accommodate both preferences or flag the conflict for manual resolution."
    },
    {
      "scenario": "A Recipient is removed from a multi-recipient Shipment after the Shipment is in-transit.",
      "expected_behavior": "Must define whether Recipients can be removed mid-transit. If allowed, routing must be recalculated. If the removed Recipient was the only remaining undelivered one, Shipment status must transition to 'Delivered'."
    },
    {
      "scenario": "Partner API receives a multi-recipient Shipment but only understands single-recipient format. The Shipment has 5 Recipients.",
      "expected_behavior": "System must apply the backward-compatibility strategy consistently. If one-payload-per-recipient: 5 payloads are sent, each appearing as a separate shipment to the partner. If primary-only: only one recipient is sent, but the partner has no visibility into the other 4. Both have significant business implications."
    },
    {
      "scenario": "Duplicate Recipients on the same Shipment (same name, same address, same phone).",
      "expected_behavior": "Must define uniqueness constraint. Are duplicate Recipients allowed (e.g., two packages to the same person at the same address)? Or must Recipients be unique by address? This is a business decision, not a technical one."
    },
    {
      "scenario": "Billing: who pays for a multi-recipient Shipment? Is it one charge or per-recipient?",
      "expected_behavior": "The billing model must be explicitly defined. A multi-stop shipment costs more than a single-stop. Per-recipient billing, flat-rate, or distance-based pricing are all valid models. This MUST be decided before implementation."
    },
    {
      "scenario": "Migration runs on 2 million rows. Midway through, the migration fails.",
      "expected_behavior": "Migration must be idempotent and resumable. Partial migration must not leave the system in a state where some shipments are in the old schema and some in the new, with queries breaking on either format."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments likely require a new pricing model (per-stop surcharges, volume discounts). Revenue opportunity from consolidating multiple single-recipient shipments into one multi-recipient shipment, reducing per-shipment overhead. Risk: if billing is not updated, multi-recipient shipments may be undercharged, creating revenue leakage. Migration of 2M records carries operational cost and potential downtime cost.",
    "operational": "VERY HIGH. This is a foundational model change. Routing engines must handle multi-stop optimization (a fundamentally harder problem than single-stop). Courier apps must display multiple stops per shipment. Dispatch logic changes. SLA tracking becomes per-recipient. Operational reporting must distinguish shipment-level vs recipient-level metrics. Warehouse packing may need to separate items by recipient within a single shipment.",
    "user": "HIGH. Couriers see a fundamentally different workflow — multiple stops per shipment instead of one. Senders get a more powerful feature but also more complexity in the creation flow. Recipients may receive partial shipments, which changes their expectation-setting. Notification systems must handle per-recipient status updates.",
    "risk": "CRITICAL. This touches the core domain model. Risks include: (1) Data migration failure on 2M records causing production outage, (2) Partner API breakage causing contractual violations, (3) Routing engine inability to handle multi-stop efficiently causing delivery delays, (4) Billing model gaps causing revenue leakage, (5) Status model ambiguity causing incorrect tracking information shown to customers. This change should be behind a feature flag with gradual rollout.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "New capability to send to multiple recipients in one shipment. Must learn new creation flow. Billing changes." },
      { "group": "Recipients", "impact": "May now receive partial deliveries. Tracking experience changes — they see their individual delivery status within a larger shipment." },
      { "group": "Couriers/Drivers", "impact": "Workflow fundamentally changes. Multi-stop routes per shipment. Must confirm delivery per recipient. Mobile app must be updated." },
      { "group": "External Partners", "impact": "API contract changes. Must either migrate to new format or receive backward-compatible payloads. Risk of integration breakage." },
      { "group": "Operations/Dispatch", "impact": "New 'Partially Delivered' state to manage. More complex SLA tracking. New failure modes to handle." },
      { "group": "Finance/Billing", "impact": "Pricing model must evolve. Revenue reporting changes. Cost allocation per recipient needed." },
      { "group": "Customer Support", "impact": "New types of inquiries: partial delivery issues, per-recipient tracking, multi-stop complaints. Training required." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is underspecified in several critical areas. The 1:N relationship change is clear, but the downstream business rules are largely undefined: billing model, partner API backward-compatibility strategy, primary recipient concept, partial failure handling, and status semantics are all ambiguous. Multiple escalations are required before acceptance criteria can be finalized. Additionally, the interaction between multi-recipient shipments and existing partner API contracts has potential contractual/legal implications that have not been reviewed.",
    "high_confidence_areas": [
      "Core cardinality change from 1:1 to 1:N is well-defined",
      "Existing data backward compatibility is a hard requirement",
      "At-least-one-recipient invariant is clear",
      "Per-recipient delivery preferences are explicitly requested"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments is entirely undefined",
      "Partner API backward-compatibility strategy is unspecified",
      "Whether a 'Primary Recipient' concept exists is ambiguous",
      "Partial delivery failure semantics are undefined",
      "Shipment-level status aggregation rules need business decision",
      "Recipient uniqueness constraints within a shipment are unstated",
      "Whether recipients can be added/removed mid-transit is unknown"
    ],
    "assumptions": [
      "The existing Recipient fields (name, address, phone) remain mandatory for all Recipients",
      "Delivery preferences are a new concept introduced alongside multi-recipient support, not a pre-existing feature",
      "The migration must be zero-downtime or near-zero-downtime given production scale",
      "External partners cannot be force-migrated simultaneously — backward compatibility is required"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "No definition of 'Primary Recipient' concept. In a multi-recipient Shipment, is one Recipient designated as primary? This affects: (1) who receives shipment-level notifications, (2) what is sent to legacy partner APIs, (3) who is the billing contact, (4) who is the fallback if other deliveries fail.",
      "affected_stakeholders": ["Senders/Shippers", "Recipients", "External Partners", "Customer Support"],
      "options": [
        "A: First Recipient in the list is implicitly primary",
        "B: Sender explicitly designates a primary Recipient",
        "C: No primary concept — all Recipients are equal peers"
      ],
      "recommendation": "Option B — explicit designation gives the sender control and provides a clear answer for all downstream systems. Option C creates ambiguity in every system that needs a single point of contact."
    },
    {
      "type": "ambiguity",
      "description": "Partner API backward-compatibility strategy is undefined. With ~2M existing shipments and active partner integrations, the system must decide how multi-recipient shipments appear to non-migrated partners.",
      "affected_stakeholders": ["External Partners", "Operations/Dispatch"],
      "options": [
        "A: Send one API payload per recipient, each appearing as a separate shipment to the partner",
        "B: Send only the primary recipient to the partner, hiding other recipients",
        "C: Version the API — partners on v1 get single-recipient format, v2 gets multi-recipient"
      ],
      "recommendation": "Option C — API versioning is the industry standard approach. It preserves backward compatibility without data loss or confusing duplication. Options A and B both lose information or create phantom shipments."
    },
    {
      "type": "ambiguity",
      "description": "Billing model for multi-recipient shipments is completely unspecified. A multi-stop delivery costs more than single-stop. Without a pricing model, the feature cannot be correctly implemented end-to-end.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Shippers"],
      "options": [
        "A: Flat rate per shipment regardless of recipient count",
        "B: Base rate + per-recipient surcharge",
        "C: Distance-based pricing across the full multi-stop route"
      ],
      "recommendation": "Option B — it is the simplest model that correctly reflects the incremental cost of additional stops. Option C is more accurate but significantly more complex. Option A incentivizes abuse by packing many recipients into one shipment."
    },
    {
      "type": "ambiguity",
      "description": "Partial delivery failure semantics are undefined. When one recipient in a multi-recipient shipment permanently fails (address unreachable, refused delivery), what happens to the overall Shipment?",
      "affected_stakeholders": ["Operations/Dispatch", "Senders/Shippers", "Customer Support"],
      "options": [
        "A: Shipment stays 'Partially Delivered' indefinitely until manually resolved",
        "B: After a timeout, Shipment transitions to 'Completed with Exceptions'",
        "C: Failed recipient is split into a new Shipment for retry"
      ],
      "recommendation": "Option B — a terminal state with exception tracking prevents shipments from lingering in limbo forever. Option C adds operational complexity but may be needed for high-value shipments."
    }
  ],

  "rejection_reasons": []
}

